let random=async t=>crypto.getRandomValues(new Uint8Array(t)),customAlphabet=(r,a)=>{let o=(2<<Math.log(r.length-1)/Math.LN2)-1,l=-~(1.6*o*a/r.length);return async()=>{let e="";for(;;){var n=crypto.getRandomValues(new Uint8Array(l));let t=l;for(;t--;)if(e+=r[n[t]&o]||"",e.length===a)return e}}},nanoid=async(e=21)=>{let n="";for(var r=crypto.getRandomValues(new Uint8Array(e));e--;){let t=63&r[e];t<36?n+=t.toString(36):t<62?n+=(t-26).toString(36).toUpperCase():t<63?n+="_":n+="-"}return n};export{nanoid,customAlphabet,random};